reg [2:0] out;
generate
  begin : cond
    initial begin : init
      reg signed [31:0] x;
      x = 2 ** 2;
      out = x[2:0];
    end
    always @* begin : proc
      reg signed [31:0] x;
      x = 2 ** 1;
      out = x[2:0];
    end
    genvar x;
    for (x = 0; x < 3; x = x + 1)
      assign out[x] = 1;
  end
endgenerate

wire [1:0] x_top = 2'b11;
generate
  begin : A
    begin : B
      wire [1:0] y = 2'b00;
    end
    begin : C
      wire [1:0] z = 2'b01;
    end
    wire [1:0] x = B.y ^ 2'b11 ^ C.z;
  end
endgenerate

